import json, re, os, sys

# Check what files exist in /tmp
tmp_files = os.listdir('/tmp')
print('Files in /tmp:')
for f in sorted(tmp_files):
    if f.endswith('.json'):
        print(f)

# Now try to load the data
papers = None
citations = None

for tmp_file in tmp_files:
    if 'query_db_66' in tmp_file or 'query_db_52' in tmp_file:
        with open(f'/tmp/{tmp_file}', 'r') as f:
            papers = json.load(f)
            print(f'Loaded papers from {tmp_file}')
    elif 'query_db_67' in tmp_file or 'query_db_53' in tmp_file:
        with open(f'/tmp/{tmp_file}', 'r') as f:
            citations = json.load(f)
            print(f'Loaded citations from {tmp_file}')

if papers and citations:
    print('Success! Papers:', len(papers), 'Citations:', len(citations))
else:
    print('Failed to find both datasets')

